	_ = v_is_audio
	_ = v_is_class
	_ = v_is_file
	_ = v_is_image
	_ = v_is_input
	_ = v_is_internal
	_ = v_is_media
	_ = v_known_type
	_ = v_media_types
	_ = v_message
