func _signature_validate_impl(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_signature Value
	var v_collision Value
	var v_duplicate Value
	var v_error Value
	var v_field Value
	var v_field_name Value
	var v_input_count Value
	var v_inputs Value
	var v_message Value
	var v_no_inputs Value
	var v_no_outputs Value
	var v_output_count Value
	var v_outputs Value
	var v_seen_inputs Value
	var v_seen_outputs Value
	if len(args) > 0 { v_signature = args[0] }
	_ = v_signature
	_ = v_collision
	_ = v_duplicate
	_ = v_error
	_ = v_field
	_ = v_field_name
	_ = v_input_count
	_ = v_inputs
	_ = v_message
	_ = v_no_inputs
	_ = v_no_outputs
	_ = v_output_count
	_ = v_outputs
	_ = v_seen_inputs
	_ = v_seen_outputs
	v_inputs = coreGet(v_signature, "input_fields", nil)
	v_outputs = coreGet(v_signature, "output_fields", nil)
	v_input_count = _core_len(v_inputs)
	v_no_inputs = _core_eq(v_input_count, 0)
	if coreTruthy(v_no_inputs) {
		v_error = _core_signature_error("No input fields specified")
		panic(asAxError(v_error))
	} else {
	// empty
	}
	v_output_count = _core_len(v_outputs)
	v_no_outputs = _core_eq(v_output_count, 0)
	if coreTruthy(v_no_outputs) {
		v_error = _core_signature_error("No output fields specified")
		panic(asAxError(v_error))
	} else {
	// empty
	}
	v_seen_inputs = MutableArray()
	for _, v_field = range coreIter(v_inputs) {
		var coreLoopSignal any
		func() {
			defer func() {
				if r := recover(); r != nil {
					switch r.(type) {
					case coreBreak, coreContinue:
						coreLoopSignal = r
					default:
						panic(r)
					}
				}
			}()
			_signature_validate_field_shape_impl(v_field, false, false)
			v_field_name = coreGet(v_field, "name", nil)
			v_duplicate = _core_contains(v_seen_inputs, v_field_name)
			if coreTruthy(v_duplicate) {
				v_message = _core_string_format("Duplicate input field name: \"{}\"", v_field_name)
				v_error = _core_signature_error(v_message)
				panic(asAxError(v_error))
			} else {
			// empty
			}
			v_seen_inputs = coreAppend(v_seen_inputs, v_field_name)
		}()
		if _, ok := coreLoopSignal.(coreBreak); ok { break }
		if _, ok := coreLoopSignal.(coreContinue); ok { continue }
	}
	v_seen_outputs = MutableArray()
	for _, v_field = range coreIter(v_outputs) {
		var coreLoopSignal any
		func() {
			defer func() {
				if r := recover(); r != nil {
					switch r.(type) {
					case coreBreak, coreContinue:
						coreLoopSignal = r
					default:
						panic(r)
					}
				}
			}()
			_signature_validate_field_shape_impl(v_field, true, false)
			v_field_name = coreGet(v_field, "name", nil)
			v_collision = _core_contains(v_seen_inputs, v_field_name)
			if coreTruthy(v_collision) {
				v_message = _core_string_format("Field name \"{}\" appears in both inputs and outputs", v_field_name)
				v_error = _core_signature_error(v_message)
				panic(asAxError(v_error))
			} else {
			// empty
			}
			v_duplicate = _core_contains(v_seen_outputs, v_field_name)
			if coreTruthy(v_duplicate) {
				v_message = _core_string_format("Duplicate output field name: \"{}\"", v_field_name)
				v_error = _core_signature_error(v_message)
				panic(asAxError(v_error))
			} else {
			// empty
			}
			v_seen_outputs = coreAppend(v_seen_outputs, v_field_name)
		}()
		if _, ok := coreLoopSignal.(coreBreak); ok { break }
		if _, ok := coreLoopSignal.(coreContinue); ok { continue }
	}
	panic(coreReturn{value: nil})
}

