func _policy_flag_enabled(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_flags Value
	var v_condition Value
	var v_always Value
	var v_discovery Value
	var v_discovery_or_skills Value
	var v_host_only Value
	var v_out Value
	var v_skills Value
	var v_value Value
	if len(args) > 0 { v_flags = args[0] }
	_ = v_flags
	if len(args) > 1 { v_condition = args[1] }
	_ = v_condition
	_ = v_always
	_ = v_discovery
	_ = v_discovery_or_skills
	_ = v_host_only
	_ = v_out
	_ = v_skills
	_ = v_value
	v_out = false
	v_always = _core_eq(v_condition, "always")
	if coreTruthy(v_always) {
		v_out = true
	} else {
		v_discovery_or_skills = _core_eq(v_condition, "discoveryMode|skillsMode")
		if coreTruthy(v_discovery_or_skills) {
			v_discovery = coreGet(v_flags, "discoveryMode", false)
			v_skills = coreGet(v_flags, "skillsMode", false)
			v_out = _core_or(v_discovery, v_skills)
		} else {
			v_host_only = _core_eq(v_condition, "host_protocol_only")
			if coreTruthy(v_host_only) {
				v_out = true
			} else {
				v_value = coreGet(v_flags, v_condition, false)
				v_out = v_value
			}
		}
	}
	panic(coreReturn{value: v_out})
}

func _select_actor_primitives(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_registry Value
	var v_stage Value
	var v_condition Value
	var v_empty_list Value
	var v_enabled Value
	var v_flags Value
	var v_in_stage Value
	var v_include Value
	var v_out Value
	var v_primitive Value
	var v_primitives Value
	var v_stages Value
	if len(args) > 0 { v_registry = args[0] }
	_ = v_registry
	if len(args) > 1 { v_stage = args[1] }
	_ = v_stage
	_ = v_condition
	_ = v_empty_list
	_ = v_enabled
	_ = v_flags
	_ = v_in_stage
	_ = v_include
	_ = v_out
	_ = v_primitive
	_ = v_primitives
	_ = v_stages
	v_empty_list = MutableArray()
	v_out = MutableArray()
	v_flags = coreGet(v_registry, "flags", v_empty_list)
	v_primitives = coreGet(v_registry, "actor_primitives", v_empty_list)
	for _, v_primitive = range coreIter(v_primitives) {
		var coreLoopSignal any
		func() {
			defer func() {
				if r := recover(); r != nil {
					switch r.(type) {
					case coreBreak, coreContinue:
						coreLoopSignal = r
					default:
						panic(r)
					}
				}
			}()
			v_stages = coreGet(v_primitive, "stages", v_empty_list)
			v_in_stage = _core_contains(v_stages, v_stage)
			v_condition = coreGet(v_primitive, "availability_condition", "always")
			v_enabled = _policy_flag_enabled(v_flags, v_condition)
			v_include = _core_and(v_in_stage, v_enabled)
			if coreTruthy(v_include) {
				v_out = coreAppend(v_out, v_primitive)
			} else {
			// empty
			}
		}()
		if _, ok := coreLoopSignal.(coreBreak); ok { break }
		if _, ok := coreLoopSignal.(coreContinue); ok { continue }
	}
	panic(coreReturn{value: v_out})
}

