			coreSet(v_event, "kind", v_action_compacted_kind)
			coreSet(v_event, "stage", "executor")
			v_turn = coreGet(v_compaction, "turn", 0)
			v_mode = coreGet(v_compaction, "mode", "compact")
			v_default_reason = _agent_context_event_reason("pressure")
