func _normalize_agent_callable(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_raw Value
	var v_namespace Value
	var v_always_camel Value
	var v_always_include Value
	var v_description Value
	var v_error Value
	var v_kind Value
	var v_missing_name Value
	var v_name Value
	var v_out Value
	var v_parameters Value
	var v_qualified Value
	if len(args) > 0 { v_raw = args[0] }
	_ = v_raw
	if len(args) > 1 { v_namespace = args[1] }
	_ = v_namespace
	_ = v_always_camel
	_ = v_always_include
	_ = v_description
	_ = v_error
	_ = v_kind
	_ = v_missing_name
	_ = v_name
	_ = v_out
	_ = v_parameters
	_ = v_qualified
	v_name = coreGet(v_raw, "name", "")
	v_missing_name = _core_eq(v_name, "")
	if coreTruthy(v_missing_name) {
		v_error = _core_runtime_error("agent callable name is required")
		panic(asAxError(v_error))
	} else {
	// empty
	}
	v_kind = coreGet(v_raw, "kind", "tool")
	v_description = coreGet(v_raw, "description", "")
	v_qualified = _core_string_format("{}.{}", v_namespace, v_name)
	v_parameters = coreGet(v_raw, "parameters", nil)
	v_always_camel = coreGet(v_raw, "alwaysInclude", false)
	v_always_include = coreGet(v_raw, "always_include", v_always_camel)
	v_out = Object()
	coreSet(v_out, "name", v_name)
	coreSet(v_out, "namespace", v_namespace)
	coreSet(v_out, "qualified_name", v_qualified)
	coreSet(v_out, "kind", v_kind)
	coreSet(v_out, "description", v_description)
	coreSet(v_out, "parameters", v_parameters)
	coreSet(v_out, "always_include", v_always_include)
	panic(coreReturn{value: v_out})
}

func _normalize_agent_group(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_raw Value
	var v_always_camel Value
	var v_always_include Value
	var v_callable Value
	var v_callables Value
	var v_conflicts Value
	var v_description Value
	var v_empty_list Value
	var v_error Value
	var v_fn Value
	var v_functions Value
	var v_message Value
	var v_name Value
	var v_namespace Value
	var v_out Value
	var v_reserved Value
	var v_selection_camel Value
	var v_selection_criteria Value
	var v_title Value
	if len(args) > 0 { v_raw = args[0] }
	_ = v_raw
	_ = v_always_camel
	_ = v_always_include
	_ = v_callable
	_ = v_callables
	_ = v_conflicts
	_ = v_description
	_ = v_empty_list
	_ = v_error
	_ = v_fn
	_ = v_functions
	_ = v_message
	_ = v_name
	_ = v_namespace
	_ = v_out
	_ = v_reserved
	_ = v_selection_camel
	_ = v_selection_criteria
	_ = v_title
	v_empty_list = MutableArray()
	v_name = coreGet(v_raw, "name", "tools")
	v_namespace = coreGet(v_raw, "namespace", v_name)
	v_reserved = _agent_reserved_runtime_names()
	v_conflicts = _core_contains(v_reserved, v_namespace)
	if coreTruthy(v_conflicts) {
		v_message = _core_string_format("agent callable namespace conflicts with reserved runtime name: {}", v_namespace)
		v_error = _core_runtime_error(v_message)
		panic(asAxError(v_error))
	} else {
	// empty
	}
	v_title = coreGet(v_raw, "title", v_namespace)
	v_description = coreGet(v_raw, "description", "")
	v_selection_camel = coreGet(v_raw, "selectionCriteria", "")
	v_selection_criteria = coreGet(v_raw, "selection_criteria", v_selection_camel)
	v_always_camel = coreGet(v_raw, "alwaysInclude", false)
	v_always_include = coreGet(v_raw, "always_include", v_always_camel)
	v_functions = coreGet(v_raw, "functions", v_empty_list)
	v_callables = MutableArray()
	for _, v_fn = range coreIter(v_functions) {
		var coreLoopSignal any
		func() {
			defer func() {
				if r := recover(); r != nil {
					switch r.(type) {
					case coreBreak, coreContinue:
						coreLoopSignal = r
					default:
						panic(r)
					}
				}
			}()
			v_callable = _normalize_agent_callable(v_fn, v_namespace)
			v_callables = coreAppend(v_callables, v_callable)
		}()
		if _, ok := coreLoopSignal.(coreBreak); ok { break }
		if _, ok := coreLoopSignal.(coreContinue); ok { continue }
	}
	v_out = Object()
	coreSet(v_out, "namespace", v_namespace)
	coreSet(v_out, "title", v_title)
	coreSet(v_out, "description", v_description)
	coreSet(v_out, "selection_criteria", v_selection_criteria)
	coreSet(v_out, "always_include", v_always_include)
	coreSet(v_out, "callables", v_callables)
	panic(coreReturn{value: v_out})
}

func _normalize_agent_callable_inventory(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_options Value
	var v_callable Value
	var v_empty_list Value
	var v_error Value
	var v_flat_callables Value
	var v_flat_count Value
	var v_flat_group Value
	var v_functions Value
	var v_group Value
	var v_group_functions Value
	var v_groups Value
	var v_has_any_flat Value
	var v_has_flat Value
	var v_has_group Value
	var v_is_group Value
	var v_item Value
	if len(args) > 0 { v_options = args[0] }
	_ = v_options
	_ = v_callable
	_ = v_empty_list
	_ = v_error
	_ = v_flat_callables
	_ = v_flat_count
	_ = v_flat_group
	_ = v_functions
	_ = v_group
	_ = v_group_functions
	_ = v_groups
	_ = v_has_any_flat
	_ = v_has_flat
	_ = v_has_group
	_ = v_is_group
	_ = v_item
	v_empty_list = MutableArray()
	v_functions = coreGet(v_options, "functions", v_empty_list)
	v_groups = MutableArray()
	v_flat_callables = MutableArray()
	v_has_flat = false
	v_has_group = false
	for _, v_item = range coreIter(v_functions) {
		var coreLoopSignal any
		func() {
			defer func() {
				if r := recover(); r != nil {
					switch r.(type) {
					case coreBreak, coreContinue:
						coreLoopSignal = r
					default:
						panic(r)
					}
				}
			}()
			v_group_functions = coreGet(v_item, "functions", nil)
			v_is_group = coreTypeIs(v_group_functions, "list")
			if coreTruthy(v_is_group) {
				v_has_group = true
				if coreTruthy(v_has_flat) {
					v_error = _core_runtime_error("agent functions cannot mix grouped modules and flat functions")
					panic(asAxError(v_error))
				} else {
				// empty
				}
				v_group = _normalize_agent_group(v_item)
				v_groups = coreAppend(v_groups, v_group)
			} else {
				v_has_flat = true
				if coreTruthy(v_has_group) {
					v_error = _core_runtime_error("agent functions cannot mix grouped modules and flat functions")
					panic(asAxError(v_error))
				} else {
				// empty
				}
				v_callable = _normalize_agent_callable(v_item, "tools")
				v_flat_callables = coreAppend(v_flat_callables, v_callable)
			}
		}()
		if _, ok := coreLoopSignal.(coreBreak); ok { break }
		if _, ok := coreLoopSignal.(coreContinue); ok { continue }
	}
	v_flat_count = _core_len(v_flat_callables)
	v_has_any_flat = _core_gt(v_flat_count, 0)
	if coreTruthy(v_has_any_flat) {
		v_flat_group = Object()
		coreSet(v_flat_group, "namespace", "tools")
		coreSet(v_flat_group, "title", "Tools")
		coreSet(v_flat_group, "description", "")
		coreSet(v_flat_group, "selection_criteria", "")
		coreSet(v_flat_group, "always_include", true)
		coreSet(v_flat_group, "callables", v_flat_callables)
		v_groups = coreAppend(v_groups, v_flat_group)
	} else {
	// empty
	}
	panic(coreReturn{value: v_groups})
}

