func _agent_replay_trace(args ...Value) (ret Value) {
	defer catchCoreReturn(&ret)
	var v_trace Value
	var v_fixtures Value
	var v_action_log Value
	var v_actual_output_text Value
	var v_actual_text Value
	var v_chat_log Value
	var v_empty_list Value
	var v_error Value
	var v_event Value
	var v_event_count Value
	var v_event_kinds Value
	var v_events Value
	var v_expected_kinds Value
	var v_expected_output Value
	var v_expected_output_text Value
	var v_expected_text Value
	var v_has_expected_kinds Value
	var v_has_expected_output Value
	var v_kind Value
	var v_matches Value
	var v_message Value
	var v_mismatch Value
	var v_out Value
	var v_output Value
	var v_output_matches Value
	var v_output_mismatch Value
	var v_status Value
	if len(args) > 0 { v_trace = args[0] }
	_ = v_trace
	if len(args) > 1 { v_fixtures = args[1] }
	_ = v_fixtures
	_ = v_action_log
	_ = v_actual_output_text
	_ = v_actual_text
	_ = v_chat_log
	_ = v_empty_list
	_ = v_error
	_ = v_event
	_ = v_event_count
	_ = v_event_kinds
	_ = v_events
	_ = v_expected_kinds
	_ = v_expected_output
	_ = v_expected_output_text
	_ = v_expected_text
	_ = v_has_expected_kinds
	_ = v_has_expected_output
	_ = v_kind
	_ = v_matches
	_ = v_message
	_ = v_mismatch
	_ = v_out
	_ = v_output
	_ = v_output_matches
	_ = v_output_mismatch
	_ = v_status
	v_empty_list = MutableArray()
	v_events = coreGet(v_trace, "events", v_empty_list)
	v_event_kinds = MutableArray()
	for _, v_event = range coreIter(v_events) {
		var coreLoopSignal any
		func() {
			defer func() {
				if r := recover(); r != nil {
					switch r.(type) {
					case coreBreak, coreContinue:
						coreLoopSignal = r
					default:
						panic(r)
					}
				}
			}()
			v_kind = coreGet(v_event, "kind", "")
			v_event_kinds = coreAppend(v_event_kinds, v_kind)
		}()
		if _, ok := coreLoopSignal.(coreBreak); ok { break }
		if _, ok := coreLoopSignal.(coreContinue); ok { continue }
	}
	v_expected_kinds = coreGet(v_fixtures, "expected_event_kinds", nil)
	v_has_expected_kinds = coreTypeIs(v_expected_kinds, "list")
	if coreTruthy(v_has_expected_kinds) {
		v_actual_text = _core_json_stringify(v_event_kinds)
		v_expected_text = _core_json_stringify(v_expected_kinds)
		v_matches = _core_eq(v_actual_text, v_expected_text)
		v_mismatch = _core_not(v_matches)
		if coreTruthy(v_mismatch) {
			v_message = _core_string_format("agent replay event sequence mismatch: expected {} got {}", v_expected_text, v_actual_text)
			v_error = _core_runtime_error(v_message)
			panic(asAxError(v_error))
		} else {
		// empty
		}
	} else {
	// empty
	}
	v_output = coreGet(v_trace, "final_output", nil)
	v_expected_output = coreGet(v_fixtures, "expected_output", nil)
	v_has_expected_output = _core_is_not_none(v_expected_output)
	if coreTruthy(v_has_expected_output) {
		v_actual_output_text = _core_json_stringify(v_output)
		v_expected_output_text = _core_json_stringify(v_expected_output)
		v_output_matches = _core_eq(v_actual_output_text, v_expected_output_text)
		v_output_mismatch = _core_not(v_output_matches)
		if coreTruthy(v_output_mismatch) {
			v_message = _core_string_format("agent replay output mismatch: expected {} got {}", v_expected_output_text, v_actual_output_text)
			v_error = _core_runtime_error(v_message)
			panic(asAxError(v_error))
		} else {
		// empty
		}
	} else {
	// empty
	}
	v_event_count = _core_len(v_events)
	v_status = coreGet(v_trace, "status", "unknown")
	v_action_log = coreGet(v_trace, "action_log", v_empty_list)
	v_chat_log = coreGet(v_trace, "chat_log", v_empty_list)
	v_out = Object()
	coreSet(v_out, "ok", true)
	coreSet(v_out, "status", "replayed")
	coreSet(v_out, "original_status", v_status)
	coreSet(v_out, "output", v_output)
	coreSet(v_out, "event_kinds", v_event_kinds)
	coreSet(v_out, "event_count", v_event_count)
	coreSet(v_out, "action_log", v_action_log)
	coreSet(v_out, "chat_log", v_chat_log)
	coreSet(v_out, "trace", v_trace)
	panic(coreReturn{value: v_out})
}

